import svg4everybody from 'svg4everybody';
import $ from 'jquery';

$(() => {
	svg4everybody();
	// Поставить инпуты (radio и checkbox) в положение checked, если у них атрибут data-check имеет значение true
	const inputs = document.querySelectorAll('[data-check="true"]');
	for (let i = 0; i < inputs.length; i++) {
		inputs[i].setAttribute('checked', 'checked');
	}
	// Слайдер
	const holder = document.querySelector('.scale__holder');
	const slider = document.querySelector('.scale__slider');
	const sliderLeftOffset = slider.getBoundingClientRect().left;
	holder.onmousedown = e => {
		const moveAt = event => {
			holder.style.left = event.pageX - sliderLeftOffset - holder.offsetWidth / 2 + 'px';
		};
		moveAt(e);
		document.onmousemove = ev => {
			moveAt(ev);
		};
		document.onmouseup = () => {
			document.onmousemove = null;
			holder.onmouseup = null;
		};
	};
	holder.ondragstart = () => {
		return false;
	};
	slider.onclick = e => {
		holder.style.left = e.pageX - sliderLeftOffset - holder.offsetWidth / 2 + 'px';
	};
});



